payload.arguments:
{"cmd":"target='[REDACTED_LOCAL_PATH]';
if [ -d "$target" ]; then
  echo "TARGET_OK=$target"
else
  echo "TARGET_MISSING=$target"
fi
if [ -L "$target" ]; then
  echo "TARGET_SYMLINK=$(readlink "$target")"
fi
pwd_dir="$(pwd)"; echo "PWD=$pwd_dir";
if [ -f "$target/.git/config" ]; then echo "TARGET_HAS_GIT=yes"; fi
# process check
proc_match=$(ps -ax -o pid=,command= | rg -n 'dws|scripts/run_daily\.sh|archive_dingtalk_all_files\.py' | sed -n '1,120p');
echo "RUNNING_DWS_PROCS<<'EOF'";
echo "$proc_match";
echo "EOF"; 
","workdir":"[REDACTED_LOCAL_PATH]","yield_time_ms":10000,"max_output_tokens":12000}
